/**
 * MMS Workers - Central Exports
 *
 * BullMQ worker infrastructure for background job processing.
 * Each worker processes jobs from its designated queue with
 * consistent error handling, tracing, and metrics.
 *
 * Worker Types:
 * - ingestion: CSV file processing and mileage data import
 * - tactical_scheduler: PM scheduling within 12-week horizon
 * - strategic_planner: Long-term (10-year) PM planning
 * - optimizer: Run assignment optimization (C++ CP-SAT or TS fallback)
 * - manhour_leveling: Workload balancing across periods
 * - drift_monitor: Baseline comparison and drift detection
 * - notification: Email and alert sending
 * - report: PDF/Excel report generation
 *
 * @see specs/004-domain-services.md Section 4.8
 * @see specs/002-architecture.md Section 2.4 - Worker Layer
 */

import { Worker, type WorkerOptions, type Job } from 'bullmq';
import { logger } from '../lib/logging/logger';
import { QUEUE_NAMES, type QueueName, type JobData } from '../lib/queue';
import { withSpan } from '../lib/tracing';
import { toMmsError, QueueError } from '../lib/errors';
import { workerMetrics } from '../lib/metrics';

// =============================================================================
// Worker Configuration
// =============================================================================

/**
 * Default worker options applied to all workers
 */
export const DEFAULT_WORKER_OPTIONS: Partial<WorkerOptions> = {
  concurrency: 1,
  autorun: true,
  lockDuration: 30000, // 30 seconds
  lockRenewTime: 15000, // 15 seconds
  limiter: undefined, // No rate limiting by default
};

/**
 * Worker-specific configurations
 */
export const WORKER_CONFIGS: Record<
  keyof typeof QUEUE_NAMES,
  { concurrency: number; lockDuration: number; description: string }
> = {
  INGESTION: {
    concurrency: 1, // Sequential to avoid race conditions
    lockDuration: 60000, // 1 minute for file processing
    description: 'CSV file processing and mileage data import',
  },
  TACTICAL_SCHEDULER: {
    concurrency: 1, // Single scheduler to maintain consistency
    lockDuration: 300000, // 5 minutes for scheduling
    description: 'PM scheduling within 12-week horizon',
  },
  STRATEGIC_PLANNER: {
    concurrency: 1, // Single planner for GA optimization
    lockDuration: 600000, // 10 minutes for long-term planning
    description: 'Long-term (10-year) PM planning with genetic algorithm',
  },
  OPTIMIZER: {
    concurrency: 2, // Can run multiple optimizations in parallel
    lockDuration: 60000, // 1 minute per optimization
    description: 'Run assignment optimization (C++ CP-SAT or TS fallback)',
  },
  MANHOUR_LEVELING: {
    concurrency: 1, // Sequential processing
    lockDuration: 120000, // 2 minutes
    description: 'Workload balancing across periods',
  },
  DRIFT_MONITOR: {
    concurrency: 2, // Can analyze multiple baselines
    lockDuration: 60000, // 1 minute
    description: 'Baseline comparison and drift detection',
  },
  NOTIFICATION: {
    concurrency: 5, // High concurrency for notifications
    lockDuration: 30000, // 30 seconds
    description: 'Email and alert sending',
  },
  REPORT: {
    concurrency: 2, // PDF/Excel generation
    lockDuration: 120000, // 2 minutes for report generation
    description: 'PDF/Excel report generation',
  },
  MAXIMO_SYNC: {
    concurrency: 1, // Sequential to avoid race conditions with Maximo
    lockDuration: 300000, // 5 minutes for sync operations
    description: 'Bidirectional sync with Maximo work order system',
  },
};

// =============================================================================
// Redis Configuration
// =============================================================================

function getRedisConfig() {
  return {
    host: process.env['REDIS_HOST'] ?? 'localhost',
    port: parseInt(process.env['REDIS_PORT'] ?? '6379', 10),
    password: process.env['REDIS_PASSWORD'],
    maxRetriesPerRequest: null as null, // Required for BullMQ
  };
}

// =============================================================================
// Base Worker Types
// =============================================================================

/**
 * Job context passed to processor functions
 */
export interface WorkerJobContext<T extends JobData = JobData> {
  /** Job ID */
  id: string;
  /** Job name */
  name: string;
  /** Job data payload */
  data: T;
  /** Job attempt number (1-based) */
  attemptsMade: number;
  /** Update job progress (0-100) */
  updateProgress: (progress: number | object) => Promise<void>;
  /** Add log message to job */
  log: (message: string) => Promise<void>;
}

/**
 * Worker processor function signature
 */
export type WorkerProcessor<T extends JobData = JobData, R = unknown> = (
  context: WorkerJobContext<T>
) => Promise<R>;

/**
 * Worker registration result
 */
export interface RegisteredWorker {
  /** Worker instance */
  worker: Worker;
  /** Queue name */
  queueName: QueueName;
  /** Worker description */
  description: string;
  /** Graceful shutdown function */
  close: () => Promise<void>;
}

// =============================================================================
// Worker Factory
// =============================================================================

const registeredWorkers: Map<QueueName, RegisteredWorker> = new Map();

/**
 * Create and register a worker for a queue
 *
 * @param queueKey - Key from QUEUE_NAMES (e.g., 'INGESTION')
 * @param processor - Function to process jobs
 * @param options - Optional worker configuration overrides
 * @returns Registered worker instance
 */
export function registerWorker<T extends JobData = JobData, R = unknown>(
  queueKey: keyof typeof QUEUE_NAMES,
  processor: WorkerProcessor<T, R>,
  options?: Partial<WorkerOptions>
): RegisteredWorker {
  const queueName = QUEUE_NAMES[queueKey];
  const config = WORKER_CONFIGS[queueKey];

  // Check if already registered
  if (registeredWorkers.has(queueName)) {
    const existing = registeredWorkers.get(queueName)!;
    logger.warn({ queueName }, 'Worker already registered, returning existing');
    return existing;
  }

  const workerOptions: WorkerOptions = {
    connection: getRedisConfig(),
    concurrency: config.concurrency,
    lockDuration: config.lockDuration,
    lockRenewTime: Math.floor(config.lockDuration / 2),
    ...options,
  };

  const worker = new Worker<T, R>(
    queueName,
    async (job: Job<T>) => {
      const startTime = Date.now();
      const jobLogger = logger.child({
        queueName,
        jobId: job.id,
        jobName: job.name,
        attemptsMade: job.attemptsMade,
      });

      jobLogger.info('Starting job processing');
      workerMetrics.queueJobStarted.labels(queueName).inc();

      try {
        const result = await withSpan(
          `worker.${queueKey.toLowerCase()}`,
          async () => {
            const workerContext: WorkerJobContext<T> = {
              id: job.id ?? 'unknown',
              name: job.name,
              data: job.data,
              attemptsMade: job.attemptsMade,
              updateProgress: async (progress) => {
                await job.updateProgress(progress);
              },
              log: async (message) => {
                await job.log(message);
                jobLogger.debug({ message }, 'Job log');
              },
            };

            return processor(workerContext);
          },
          {
            attributes: {
              queueName,
              jobId: job.id ?? 'unknown',
              jobName: job.name,
            },
          }
        );

        const durationMs = Date.now() - startTime;
        jobLogger.info({ durationMs }, 'Job completed successfully');
        workerMetrics.queueJobCompleted.labels(queueName).inc();
        workerMetrics.queueJobDuration.labels(queueName).observe(durationMs / 1000);

        return result;
      } catch (error) {
        const durationMs = Date.now() - startTime;
        const mmsError = toMmsError(error);

        jobLogger.error(
          {
            error: mmsError.message,
            code: mmsError.code,
            durationMs,
          },
          'Job failed'
        );

        workerMetrics.queueJobFailed.labels(queueName).inc();

        throw new QueueError(`Job ${job.id} failed: ${mmsError.message}`, {
          queueName,
          jobId: job.id,
          context: {
            attemptsMade: job.attemptsMade,
            originalError: mmsError.code,
          },
        });
      }
    },
    workerOptions
  );

  // Register event handlers
  worker.on('ready', () => {
    logger.info({ queueName, concurrency: workerOptions.concurrency }, 'Worker ready');
  });

  worker.on('error', (error) => {
    logger.error({ queueName, error: error.message }, 'Worker error');
  });

  worker.on('stalled', (jobId) => {
    logger.warn({ queueName, jobId }, 'Job stalled');
    workerMetrics.queueJobFailed.labels(queueName).inc();
  });

  const registeredWorker: RegisteredWorker = {
    worker,
    queueName,
    description: config.description,
    close: async () => {
      logger.info({ queueName }, 'Closing worker');
      await worker.close();
      registeredWorkers.delete(queueName);
    },
  };

  registeredWorkers.set(queueName, registeredWorker);
  logger.info({ queueName, description: config.description }, 'Worker registered');

  return registeredWorker;
}

/**
 * Get a registered worker by queue key
 */
export function getWorker(queueKey: keyof typeof QUEUE_NAMES): RegisteredWorker | undefined {
  return registeredWorkers.get(QUEUE_NAMES[queueKey]);
}

/**
 * Get all registered workers
 */
export function getAllWorkers(): RegisteredWorker[] {
  return Array.from(registeredWorkers.values());
}

/**
 * Close all registered workers gracefully
 */
export async function closeAllWorkers(): Promise<void> {
  logger.info({ count: registeredWorkers.size }, 'Closing all workers');

  const closePromises: Promise<void>[] = [];
  for (const worker of registeredWorkers.values()) {
    closePromises.push(worker.close());
  }

  await Promise.all(closePromises);
  logger.info('All workers closed');
}

// =============================================================================
// Health Check
// =============================================================================

/**
 * Worker health status
 */
export interface WorkerHealth {
  queueName: QueueName;
  description: string;
  isRunning: boolean;
  isPaused: boolean;
}

/**
 * Get health status of all workers
 */
export async function getWorkersHealth(): Promise<WorkerHealth[]> {
  const health: WorkerHealth[] = [];

  for (const [queueName, registered] of registeredWorkers.entries()) {
    health.push({
      queueName,
      description: registered.description,
      isRunning: registered.worker.isRunning(),
      isPaused: registered.worker.isPaused(),
    });
  }

  return health;
}

// =============================================================================
// Re-exports for convenience
// =============================================================================

export {
  QUEUE_NAMES,
  type QueueName,
  type JobData,
  type IngestionJobData,
  type TacticalSchedulerJobData,
