/**
 * MMS Worker Runner Tests
 *
 * Tests for the worker daemon runner and worker registration.
 *
 * @see specs/004-domain-services.md Section 4.8
 */

import { describe, expect, it, mock } from 'bun:test';
import { WORKER_PROCESSORS } from './runner';
import { QUEUE_NAMES } from '../lib/queue';

// =============================================================================
// Test Setup
// =============================================================================

// Mock Redis to avoid actual connections
mock.module('ioredis', () => ({
  default: class MockRedis {
    ping() {
      return Promise.resolve('PONG');
    }
    quit() {
      return Promise.resolve();
    }
    on() {
      return this;
    }
    disconnect() {
      return Promise.resolve();
    }
  },
}));

// Mock BullMQ Worker to avoid actual queue connections
mock.module('bullmq', () => ({
  Worker: class MockWorker {
    constructor(
      public name: string,
      public processor: unknown,
      public options: unknown
    ) {}
    isRunning() {
      return true;
    }
    isPaused() {
      return false;
    }
    on() {
      return this;
    }
    close() {
      return Promise.resolve();
    }
  },
  Queue: class MockQueue {
    constructor(public name: string) {}
    add() {
      return Promise.resolve({ id: 'mock-job-id' });
    }
    close() {
      return Promise.resolve();
    }
  },
}));

// =============================================================================
// Tests
// =============================================================================

describe('Worker Runner', () => {
  describe('WORKER_PROCESSORS registry', () => {
    it('should have entries for all queue names', () => {
      const queueKeys = Object.keys(QUEUE_NAMES);
      const processorKeys = Object.keys(WORKER_PROCESSORS);

      // All queue names should have a processor entry
      for (const key of queueKeys) {
        expect(processorKeys).toContain(key);
      }
    });

    it('should have optimizer processor implemented', () => {
      expect(WORKER_PROCESSORS.OPTIMIZER).not.toBeNull();
      expect(typeof WORKER_PROCESSORS.OPTIMIZER).toBe('function');
    });

    it('should have drift monitor processor implemented', () => {
      expect(WORKER_PROCESSORS.DRIFT_MONITOR).not.toBeNull();
      expect(typeof WORKER_PROCESSORS.DRIFT_MONITOR).toBe('function');
    });

    it('should have ingestion processor implemented', () => {
      expect(WORKER_PROCESSORS.INGESTION).not.toBeNull();
      expect(typeof WORKER_PROCESSORS.INGESTION).toBe('function');
    });

    it('should have tactical scheduler processor implemented', () => {
      expect(WORKER_PROCESSORS.TACTICAL_SCHEDULER).not.toBeNull();
      expect(typeof WORKER_PROCESSORS.TACTICAL_SCHEDULER).toBe('function');
    });

    it('should have strategic planner processor implemented', () => {
      expect(WORKER_PROCESSORS.STRATEGIC_PLANNER).not.toBeNull();
      expect(typeof WORKER_PROCESSORS.STRATEGIC_PLANNER).toBe('function');
    });

    it('should have manhour leveling processor implemented', () => {
      expect(WORKER_PROCESSORS.MANHOUR_LEVELING).not.toBeNull();
      expect(typeof WORKER_PROCESSORS.MANHOUR_LEVELING).toBe('function');
    });

    it('should have notification processor implemented', () => {
      expect(WORKER_PROCESSORS.NOTIFICATION).not.toBeNull();
      expect(typeof WORKER_PROCESSORS.NOTIFICATION).toBe('function');
    });

    it('should have report processor implemented', () => {
      expect(WORKER_PROCESSORS.REPORT).not.toBeNull();
      expect(typeof WORKER_PROCESSORS.REPORT).toBe('function');
    });

    it('should have maximo sync processor implemented', () => {
      expect(WORKER_PROCESSORS.MAXIMO_SYNC).not.toBeNull();
      expect(typeof WORKER_PROCESSORS.MAXIMO_SYNC).toBe('function');
    });
  });

  describe('Queue Names', () => {
    it('should have all 9 queue names defined', () => {
      expect(Object.keys(QUEUE_NAMES)).toHaveLength(9);
    });

    it('should have correct queue name values with mms prefix', () => {
      expect(QUEUE_NAMES.INGESTION).toBe('mms:ingestion');
      expect(QUEUE_NAMES.TACTICAL_SCHEDULER).toBe('mms:tactical-scheduler');
      expect(QUEUE_NAMES.STRATEGIC_PLANNER).toBe('mms:strategic-planner');
      expect(QUEUE_NAMES.OPTIMIZER).toBe('mms:optimizer');
      expect(QUEUE_NAMES.MANHOUR_LEVELING).toBe('mms:manhour-leveling');
      expect(QUEUE_NAMES.DRIFT_MONITOR).toBe('mms:drift-monitor');
      expect(QUEUE_NAMES.NOTIFICATION).toBe('mms:notification');
      expect(QUEUE_NAMES.REPORT).toBe('mms:report');
      expect(QUEUE_NAMES.MAXIMO_SYNC).toBe('mms:maximo-sync');
    });
  });
});

describe('Processor Functions', () => {
  describe('processOptimizerJob', () => {
    it('should be exported from optimizer processor', async () => {
      const { processOptimizerJob } = await import('./processors/optimizer');
      expect(typeof processOptimizerJob).toBe('function');
    });
  });

  describe('processDriftMonitorJob', () => {
    it('should be exported from drift-monitor processor', async () => {
      const { processDriftMonitorJob } = await import('./processors/drift-monitor');
      expect(typeof processDriftMonitorJob).toBe('function');
    });
  });

  describe('processIngestionJob', () => {
    it('should be exported from ingestion processor', async () => {
      const { processIngestionJob } = await import('./processors/ingestion');
      expect(typeof processIngestionJob).toBe('function');
    });
  });

  describe('processMaximoSyncJob', () => {
    it('should be exported from maximo-sync processor', async () => {
      const { processMaximoSyncJob } = await import('./processors/maximo-sync');
      expect(typeof processMaximoSyncJob).toBe('function');
    });
  });

  describe('processStrategicPlannerJob', () => {
    it('should be exported from strategic-planner processor', async () => {
      const { processStrategicPlannerJob } = await import('./processors/strategic-planner');
      expect(typeof processStrategicPlannerJob).toBe('function');
    });
  });

  describe('processNotificationJob', () => {
    it('should be exported from notification processor', async () => {
      const { processNotificationJob } = await import('./processors/notification');
      expect(typeof processNotificationJob).toBe('function');
    });
  });
});

